B.Lo=new A.O(B.O,['\u0643\u0644\u0645\u0629 "\u062c\u0647\u0627\u062f" \u062a\u0639\u0646\u064a "\u0627\u0644\u0628\u0630\u0644 \u0648\u0627\u0644\u0645\u062c\u0627\u0647\u062f\u0629". \u0623\u0639\u0644\u0649 \u062f\u0631\u062c\u0627\u062a\u0647 \u0647\u0648 "\u062c\u0647\u0627\u062f \u0627\u0644\u0646\u0641\u0633" \u2014 \u0645\u0642\u0627\u0648\u0645\u0629 \u0627\u0644\u0623\u0647\u0648\u0627\u0621 \u0648\u062a\u062d\u0633\u064a\u0646 \u0627\u0644\u0623\u062e\u0644\u0627\u0642. \u0642\u0627\u0644 \u0627\u0644\u0646\u0628\u064a \ufdfa \u0639\u0646\u062f \u0639\u0648\u062f\u062a\u0647 \u0645\u0646 \u0645\u0639\u0631\u0643\u0629: "\u0631\u062c\u0639\u0646\u0627 \u0645\u0646 \u0627\u0644\u062c\u0647\u0627\u062f \u0627\u0644\u0623\u0635\u063a\u0631 \u0625\u0644\u0649 \u0627\u0644\u062c\u0647\u0627\u062f \u0627\u0644\u0623\u0643\u0628\u0631 \u2014 \u062c\u0647\u0627\u062f \u0627\u0644\u0646\u0641\u0633".','Le mot "Jihad" signifie "effort et lutte". Sa plus haute forme est le "Jihad de l\'\xe2me" \u2014 r\xe9sister aux d\xe9sirs et am\xe9liorer son caract\xe8re.','The word "Jihad" means "striving and effort". Its highest form is the "Jihad of the soul" \u2014 resisting desires and improving character.'],t.w)
