B.Lx=new A.O(B.O,["\u0645\u0627 \u0645\u0639\u0646\u0649 \u0627\u0644\u0632\u0643\u0627\u0629 \u0648\u0643\u064a\u0641 \u062a\u0633\u0627\u0647\u0645 \u0641\u064a \u0627\u0644\u0639\u062f\u0627\u0644\u0629\u061f","Que signifie la Zakat et comment contribue-t-elle \xe0 la justice?","What is Zakat and how does it contribute to social justice?"],t.w)
B.Lv=new A.O(B.O,["\u0627\u0644\u0632\u0643\u0627\u0629 \u0647\u064a \u0625\u0639\u0637\u0627\u0621 2.5% \u0645\u0646 \u0627\u0644\u0645\u062f\u062e\u0631\u0627\u062a \u0644\u0644\u0641\u0642\u0631\u0627\u0621 \u0633\u0646\u0648\u064a\u0627\u064b. \u0647\u064a \u0631\u0643\u0646 \u0645\u0646 \u0623\u0631\u0643\u0627\u0646 \u0627\u0644\u0625\u0633\u0644\u0627\u0645 \u0648\u062a\u064f\u0637\u0647\u0651\u0631 \u0627\u0644\u0645\u0627\u0644 \u0648\u062a\u064f\u0632\u0643\u0651\u064a \u0627\u0644\u0646\u0641\u0633. \u0644\u0648 \u0637\u064f\u0628\u0651\u0642\u062a \u0627\u0644\u0632\u0643\u0627\u0629 \u0639\u0627\u0644\u0645\u064a\u0627\u064b \u0644\u0623\u0645\u0643\u0646 \u0627\u0644\u0642\u0636\u0627\u0621 \u0639\u0644\u0649 \u0627\u0644\u0641\u0642\u0631 \u0627\u0644\u0645\u062f\u0642\u0639!","La Zakat est de donner 2,5% de ses \xe9conomies aux pauvres annuellement. C'est un pilier de l'Islam qui purifie la richesse et l'\xe2me.","Zakat is giving 2.5% of savings to the poor annually. It is a pillar of Islam that purifies wealth and the soul."],t.w)
