B.LF=new A.O(B.O,["\u0627\u0644\u062c\u0646\u0629 \u0641\u064a \u0627\u0644\u0625\u0633\u0644\u0627\u0645 \u062f\u0627\u0631 \u0627\u0644\u062e\u0644\u062f \u0648\u0627\u0644\u0646\u0639\u064a\u0645 \u0627\u0644\u0623\u0628\u062f\u064a. \u064a\u0642\u0648\u0644 \u0627\u0644\u0642\u0631\u0622\u0646: \ufd3f\u0641\u0650\u064a\u0647\u064e\u0627 \u0645\u064e\u0627 \u062a\u064e\u0634\u0652\u062a\u064e\u0647\u0650\u064a\u0647\u0650 \u0627\u0644\u0652\u0623\u064e\u0646\u0641\u064f\u0633\u064f \u0648\u064e\u062a\u064e\u0644\u064e\u0630\u064f\u0651 \u0627\u0644\u0652\u0623\u064e\u0639\u0652\u064a\u064f\u0646\u064f\ufd3e. \u0644\u0643\u0646 \u0623\u0639\u0638\u0645 \u0646\u0639\u064a\u0645\u0647\u0627 \u0647\u0648 \u0631\u0624\u064a\u0629 \u0627\u0644\u0644\u0647 \u062a\u0639\u0627\u0644\u0649.",'Le Paradis en Islam est la demeure \xe9ternelle de bonheur. Le Coran dit: "Il y aura l\xe0 ce que les \xe2mes d\xe9sirent." Mais le plus grand bonheur est de voir Allah.','Paradise in Islam is the eternal abode of bliss. The Quran says: "In it is what souls desire and what delights the eyes." The greatest joy is seeing Allah.'],t.w)
