B.Lj=new A.O(B.O,["\u0643\u064a\u0641 \u064a\u064f\u0639\u0632\u0632 \u0627\u0644\u0625\u0633\u0644\u0627\u0645 \u0627\u0644\u0623\u062e\u0644\u0627\u0642 \u0627\u0644\u062d\u0633\u0646\u0629\u061f","Comment l'Islam promeut-il les bonnes m\u0153urs?","How does Islam promote good character?"],t.w)
B.LD=new A.O(B.O,['\u0642\u0627\u0644 \u0627\u0644\u0646\u0628\u064a \ufdfa: "\u0625\u0646\u0645\u0627 \u0628\u064f\u0639\u062b\u062a \u0644\u0623\u062a\u0645\u0645 \u0645\u0643\u0627\u0631\u0645 \u0627\u0644\u0623\u062e\u0644\u0627\u0642". \u0627\u0644\u0625\u0633\u0644\u0627\u0645 \u064a\u0623\u0645\u0631 \u0628\u0627\u0644\u0635\u062f\u0642 \u0648\u0627\u0644\u0623\u0645\u0627\u0646\u0629 \u0648\u0627\u0644\u0643\u0631\u0645 \u0648\u0627\u0644\u0639\u062f\u0644 \u0648\u0627\u0644\u0631\u062d\u0645\u0629. "\u062e\u064a\u0631\u0643\u0645 \u062e\u064a\u0631\u0643\u0645 \u0644\u0623\u0647\u0644\u0647"\u060c "\u0627\u0644\u062f\u064a\u0646 \u0627\u0644\u0645\u0639\u0627\u0645\u0644\u0629".',"Le Proph\xe8te \ufdfa a dit: \"Je n'ai \xe9t\xe9 envoy\xe9 que pour parfaire les bonnes m\u0153urs.\" L'Islam ordonne l'honn\xeatet\xe9, la fid\xe9lit\xe9, la g\xe9n\xe9rosit\xe9, la justice et la mis\xe9ricorde.",'The Prophet \ufdfa said: "I was sent only to perfect good character." Islam commands honesty, trustworthiness, generosity, justice and mercy.'],t.w)
