B.LI=new A.O(B.O,["\u0644\u0645\u0627\u0630\u0627 \u064a\u062f\u0639\u0648 \u0627\u0644\u0625\u0633\u0644\u0627\u0645 \u0625\u0644\u0649 \u0627\u0644\u062a\u0639\u0627\u064a\u0634 \u0645\u0639 \u063a\u064a\u0631 \u0627\u0644\u0645\u0633\u0644\u0645\u064a\u0646\u061f","Pourquoi l'Islam appelle-t-il \xe0 la coexistence?","Why does Islam call for coexistence with non-Muslims?"],t.w)
B.LP=new A.O(B.O,["\u0627\u0644\u0625\u0633\u0644\u0627\u0645 \u064a\u0623\u0645\u0631 \u0628\u0627\u0644\u0639\u062f\u0644 \u0645\u0639 \u0627\u0644\u062c\u0645\u064a\u0639. \u0642\u0627\u0644 \u062a\u0639\u0627\u0644\u0649: \ufd3f\u0644\u064e\u0627 \u064a\u064e\u0646\u0652\u0647\u064e\u0627\u0643\u064f\u0645\u064f \u0627\u0644\u0644\u064e\u0651\u0647\u064f \u0639\u064e\u0646\u0650 \u0627\u0644\u064e\u0651\u0630\u0650\u064a\u0646\u064e \u0644\u064e\u0645\u0652 \u064a\u064f\u0642\u064e\u0627\u062a\u0650\u0644\u064f\u0648\u0643\u064f\u0645\u0652 \u0641\u0650\u064a \u0627\u0644\u062f\u0650\u0651\u064a\u0646\u0650 \u0623\u064e\u0646 \u062a\u064e\u0628\u064e\u0631\u064f\u0651\u0648\u0647\u064f\u0645\u0652 \u0648\u064e\u062a\u064f\u0642\u0652\u0633\u0650\u0637\u064f\u0648\u0627 \u0625\u0650\u0644\u064e\u064a\u0652\u0647\u0650\u0645\u0652\ufd3e. \u0639\u0627\u0634 \u0641\u064a \u0638\u0644 \u0627\u0644\u062d\u0636\u0627\u0631\u0629 \u0627\u0644\u0625\u0633\u0644\u0627\u0645\u064a\u0629 \u064a\u0647\u0648\u062f \u0648\u0645\u0633\u064a\u062d\u064a\u0648\u0646 \u0628\u0633\u0644\u0627\u0645 \u0644\u0642\u0631\u0648\u0646.","L'Islam ordonne la justice envers tous. Allah dit: \"Allah ne vous interdit pas d'\xeatre bons et \xe9quitables envers ceux qui ne vous ont pas combattus.\"",'Islam commands justice towards everyone. Allah says: "Allah does not forbid you from being kind and just to those who have not fought you."'],t.w)
